  1020→  function extrairJson(texto) {
  1021→    // Procura o bloco JSON mais externo (robusto a qualquer ordenação de chaves)
  1022→    var start = texto.indexOf('{');
  1023→    if (start === -1) return null;
  1024→    // Encontra o fechamento correto contando chaves
  1025→    var depth = 0, end = -1;
  1026→    for (var i = start; i < texto.length; i++) {
  1027→      if (texto[i] === '{') depth++;
  1028→      else if (texto[i] === '}') { depth--; if (depth === 0) { end = i; break; } }
  1029→    }
  1030→    if (end === -1) return null;
  1031→    try {
  1032→      var obj = JSON.parse(texto.substring(start, end + 1));
  1033→      if (obj.type === 'questions' || obj.type === 'prompt') return obj;
  1034→      return null;
  1035→    } catch (e) { return null; }
  1036→  }
